#include <stdio.h>
#include <stdlib.h>

int compareInt(const void *a, const void *b) {
    return (*(int*)a) - (*(int*)b);
}

int minConferenceRooms(int *start, int *end, int n) {
    qsort(start, n, sizeof(int), compareInt);
    qsort(end, n, sizeof(int), compareInt);
    int i = 0, j = 0, rooms = 0, maxRooms = 0;
    while (i < n && j < n) {
        if (start[i] < end[j]) {
            rooms++;
            i++;
        } else {
            rooms--;
            j++;
        }
        if (rooms > maxRooms) maxRooms = rooms;
    }
    return maxRooms;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int *start = (int*)malloc(N * sizeof(int));
        int *end = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &start[i]);
        for (int i = 0; i < N; ++i) scanf("%d", &end[i]);
        printf("%d
", minConferenceRooms(start, end, N));
        free(start);
        free(end);
    }
    return 0;
}

