#include <bits/stdc++.h>
using namespace std;

int minConferenceRooms(vector<int> &start, vector<int> &end) {
    sort(start.begin(), start.end());
    sort(end.begin(), end.end());
    int i = 0, j = 0, rooms = 0, maxRooms = 0;
    int n = start.size();
    while (i < n && j < n) {
        if (start[i] < end[j]) {
            ++rooms; ++i;
        } else {
            --rooms; ++j;
        }
        maxRooms = max(maxRooms, rooms);
    }
    return maxRooms;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    while (T--) {
        int N; cin >> N;
        vector<int> start(N), end(N);
        for (int i = 0; i < N; ++i) cin >> start[i];
        for (int i = 0; i < N; ++i) cin >> end[i];
        cout << minConferenceRooms(start, end) << '
';
    }
    return 0;
}

