import java.io.*;
import java.util.*;

public class Main {
    private static int minConferenceRooms(int[] start, int[] end) {
        Arrays.sort(start);
        Arrays.sort(end);
        int i = 0, j = 0, rooms = 0, maxRooms = 0;
        int n = start.length;
        while (i < n && j < n) {
            if (start[i] < end[j]) {
                rooms++; i++;
            } else {
                rooms--; j++;
            }
            if (rooms > maxRooms) maxRooms = rooms;
        }
        return maxRooms;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            int[] start = new int[N];
            int[] end = new int[N];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) start[i] = Integer.parseInt(st.nextToken());
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) end[i] = Integer.parseInt(st.nextToken());
            sb.append(minConferenceRooms(start, end)).append('
');
        }
        System.out.print(sb.toString());
    }
